 1	import React, { FC } from 'react';
 2	
 3	import {
 4	  FormHelperText,
 5	  HelperText,
 6	  HelperTextItem,
 7	  ValidatedOptions,
 8	} from '@patternfly/react-core';
 9	import { ExclamationCircleIcon } from '@patternfly/react-icons';
10	
11	type FormGroupHelperTextProps = {
12	  validated?: ValidatedOptions;
13	};
14	
15	const FormGroupHelperText: FC<FormGroupHelperTextProps> = ({
16	  children,
17	  validated = ValidatedOptions.default,
18	}) => (
19	  <FormHelperText>
20	    <HelperText>
21	      <HelperTextItem
22	        icon={validated === ValidatedOptions.error && <ExclamationCircleIcon color="red" />}
23	        variant={validated}
24	      >
25	        {children}
26	      </HelperTextItem>
27	    </HelperText>
28	  </FormHelperText>
29	);
30	
31	export default FormGroupHelperText;

